#!/usr/bin/env python3
"""
generar_dashboard.py - BenchmarkCMF Dashboard Generator
Lee CMF_Tarjetas_Consolidado.xlsx y genera dashboard/index.html

Uso:
  python generar_dashboard.py
  python generar_dashboard.py --consolidado CMF_Tarjetas_Consolidado.xlsx
"""

import pandas as pd
import json, argparse, os, sys, re
import base64 as b64lib

BANKS = ["Banco de Chile", "Santander", "BCI", "BancoEstado", "Itaú", "Scotiabank"]
KPIS_C = ["Tarjetas Vigentes", "Tarjetas con Operaciones", "Monto Compras", "Nro Compras",
          "Monto Avances Efectivo", "Nro Avances Efectivo", "Monto Cargos Servicios", "Nro Cargos Servicios"]
KPIS_D = ["Tarjetas Vigentes", "Tarjetas con Operaciones", "Monto Transacciones", "Nro Transacciones",
          "Monto Giros", "Nro Giros"]
TA = {"Total": "X", "Titular": "T", "Adicional": "A"}


def extract_data(path, n_months=24, col_path=None):
    print(f"  Leyendo {path}...")
    df = pd.read_excel(path, sheet_name='Data')
    bdf = df[(df['Emisor_Comercial'].isin(BANKS)) & (df['Apertura'] == 'Emisor')]
    months_all = sorted(bdf['Fecha'].unique())
    last_n = months_all[-n_months:]
    months = [pd.Timestamp(m).strftime('%Y-%m') for m in last_n]
    bi = {b: i for i, b in enumerate(BANKS)}
    kpis = sorted(set(KPIS_C + KPIS_D))
    ki = {k: i for i, k in enumerate(kpis)}
    mi = {m: i for i, m in enumerate(months)}
    print(f"  Periodo: {months[0]} a {months[-1]} ({len(months)} meses)")

    # S_ALL
    print("  Extrayendo snapshots mensuales...")
    s_all = []
    for m in last_n:
        ms = pd.Timestamp(m).strftime('%Y-%m')
        mdf = bdf[bdf['Fecha'] == m]
        for b in BANKS:
            bk = mdf[mdf['Emisor_Comercial'] == b]
            for kl, pn in [(KPIS_C, 'Credito'), (KPIS_D, 'Debito')]:
                pc = 'C' if pn == 'Credito' else 'D'
                for kpi in kl:
                    for tl in ['Total', 'Titular', 'Adicional']:
                        r = bk[(bk['Producto']==pn)&(bk['Nombre_KPI']==kpi)&(bk['Titular_Adicional']==tl)]
                        if len(r) > 0:
                            s_all.append([mi[ms], bi[b], pc, TA[tl], ki[kpi], round(float(r.iloc[0]['Valor_KPI']))])

    # MS mensual
    print("  Calculando market share mensual...")
    ms_all = {}
    for key, pn, kn in [('cards_c','Credito','Tarjetas Vigentes'),('cards_d','Debito','Tarjetas Vigentes'),
        ('ops_c','Credito','Tarjetas con Operaciones'),('ops_d','Debito','Tarjetas con Operaciones'),
        ('spend_c','Credito','Monto Compras'),('spend_d','Debito','Monto Transacciones'),
        ('nops_c','Credito','Nro Compras'),('nops_d','Debito','Nro Transacciones')]:
        ms_all[key] = []
        for m in last_n:
            ms2 = pd.Timestamp(m).strftime('%Y-%m')
            pdf = bdf[(bdf['Fecha']==m)&(bdf['Titular_Adicional']=='Total')&(bdf['Producto']==pn)]
            vals = {}
            for b in BANKS:
                r = pdf[(pdf['Emisor_Comercial']==b)&(pdf['Nombre_KPI']==kn)]
                if len(r)>0: vals[b] = float(r.iloc[0]['Valor_KPI'])
            tot = sum(vals.values()) or 1
            for b, v in vals.items():
                ms_all[key].append([ms2, bi[b], round(v/tot*100,1), round(v)])

    # DT trimestral
    print("  Calculando metricas derivadas trimestrales...")
    qm = {3:'Q1',6:'Q2',9:'Q3',12:'Q4'}
    qms = [m for m in months_all if pd.Timestamp(m).month in [3,6,9,12] and pd.Timestamp(m).year >= 2020]
    dt_c = []
    for m in qms:
        ts = pd.Timestamp(m); ql = f"{ts.year}{qm[ts.month]}"
        pdf = bdf[(bdf['Fecha']==m)&(bdf['Titular_Adicional']=='Total')&(bdf['Producto']=='Credito')]
        for b in BANKS:
            bk = pdf[pdf['Emisor_Comercial']==b]
            def gv(k):
                r=bk[bk['Nombre_KPI']==k]; return float(r.iloc[0]['Valor_KPI']) if len(r)>0 else None
            tv,to,mc,nc,mcs,ncs = gv('Tarjetas Vigentes'),gv('Tarjetas con Operaciones'),gv('Monto Compras'),gv('Nro Compras'),gv('Monto Cargos Servicios'),gv('Nro Cargos Servicios')
            if tv and to and mc and nc:
                dt_c.append([ql,bi[b],round(to/tv*100,1),round(mc/nc*1e6),round(mc/to*1e6),round(nc/to,1),round(mcs/ncs*1e6) if mcs and ncs and ncs>0 else None])
    dt_d = []
    for m in qms:
        ts = pd.Timestamp(m); ql = f"{ts.year}{qm[ts.month]}"
        pdf = bdf[(bdf['Fecha']==m)&(bdf['Titular_Adicional']=='Total')&(bdf['Producto']=='Debito')]
        for b in BANKS:
            bk = pdf[pdf['Emisor_Comercial']==b]
            def gv(k):
                r=bk[bk['Nombre_KPI']==k]; return float(r.iloc[0]['Valor_KPI']) if len(r)>0 else None
            tv,to,mt,nt,mg,ng = gv('Tarjetas Vigentes'),gv('Tarjetas con Operaciones'),gv('Monto Transacciones'),gv('Nro Transacciones'),gv('Monto Giros'),gv('Nro Giros')
            if tv and to and mt and nt:
                dt_d.append([ql,bi[b],round(to/tv*100,1),round(mt/nt*1e6),round(mt/to*1e6),round(nt/to,1),round(mg/(mt+mg)*100,1) if mg and mt else None,round(mg/ng*1e6) if mg and ng and ng>0 else None])

    # CS trimestral
    print("  Calculando cross-sell trimestral...")
    cs = []
    for m in qms:
        ts = pd.Timestamp(m); ql = f"{ts.year}{qm[ts.month]}"
        mda = bdf[(bdf['Fecha']==m)&(bdf['Titular_Adicional']=='Total')]
        for b in BANKS:
            cr = mda[(mda['Emisor_Comercial']==b)&(mda['Producto']=='Credito')]
            de = mda[(mda['Emisor_Comercial']==b)&(mda['Producto']=='Debito')]
            def gc(k):
                r=cr[cr['Nombre_KPI']==k]; return float(r.iloc[0]['Valor_KPI']) if len(r)>0 else None
            def gd(k):
                r=de[de['Nombre_KPI']==k]; return float(r.iloc[0]['Valor_KPI']) if len(r)>0 else None
            tcv,tdv,tco,tdo = gc('Tarjetas Vigentes'),gd('Tarjetas Vigentes'),gc('Tarjetas con Operaciones'),gd('Tarjetas con Operaciones')
            mc,mt,nc,nt = gc('Monto Compras'),gd('Monto Transacciones'),gc('Nro Compras'),gd('Nro Transacciones')
            if tcv and tdv and mc and mt:
                cs.append([ql,bi[b],round(tcv/tdv*100,1),round(tco/tdo*100,1) if tco and tdo else None,round(mc/mt*100,1),round(mc/(mc+mt)*100,1),round(nc/(nc+nt)*100,1) if nc and nt else None])

    # AVM mensual
    print("  Calculando avances/giros mensuales...")
    avm = []
    for m in last_n:
        ms2 = pd.Timestamp(m).strftime('%Y-%m')
        for b in BANKS:
            mb = bdf[(bdf['Fecha']==m)&(bdf['Emisor_Comercial']==b)&(bdf['Titular_Adicional']=='Total')]
            def gvc(k):
                r=mb[(mb['Producto']=='Credito')&(mb['Nombre_KPI']==k)]; return float(r.iloc[0]['Valor_KPI']) if len(r)>0 else None
            def gvd(k):
                r=mb[(mb['Producto']=='Debito')&(mb['Nombre_KPI']==k)]; return float(r.iloc[0]['Valor_KPI']) if len(r)>0 else None
            mc,ma,na_ = gvc('Monto Compras'),gvc('Monto Avances Efectivo'),gvc('Nro Avances Efectivo')
            mt,mg,ng = gvd('Monto Transacciones'),gvd('Monto Giros'),gvd('Nro Giros')
            avm.append([ms2,bi[b],round(ma/(mc+ma)*100,1) if ma and mc else None,round(ma/na_*1e6) if ma and na_ and na_>0 else None,round(mg/(mt+mg)*100,1) if mg and mt else None,round(mg/ng*1e6) if mg and ng and ng>0 else None])

    # ADM mensual
    print("  Calculando adicionales mensuales...")
    adm = []
    for m in last_n:
        ms2 = pd.Timestamp(m).strftime('%Y-%m')
        for b in BANKS:
            for pc, pn in [('C','Credito'),('D','Debito')]:
                tv = av = None
                for tl in ['Total','Adicional']:
                    r = bdf[(bdf['Fecha']==m)&(bdf['Emisor_Comercial']==b)&(bdf['Producto']==pn)&(bdf['Nombre_KPI']=='Tarjetas Vigentes')&(bdf['Titular_Adicional']==tl)]
                    if len(r)>0:
                        val = float(r.iloc[0]['Valor_KPI'])
                        if tl=='Total': tv=val
                        else: av=val
                if tv and av: adm.append([ms2,bi[b],pc,round(av/tv*100,1)])

    col_data = extract_col_data(col_path)
    compact = {'M':months,'B':BANKS,'K':kpis,'S':s_all,'MS':ms_all,'MSM':ms_all,'DT':dt_c,'DTD':dt_d,'CS':cs,'AVM':avm,'ADM':adm,
               'MORA':_MORA_DATA,'CV':_CV_DATA,'COL':col_data}
    data_json = json.dumps(compact, separators=(',',':'))
    print(f"  Data JSON: {len(data_json):,} bytes ({len(data_json)//1024} KB)")
    return data_json, months[-1]


