def extract_col_data(col_path):
    """Lee api_cmf_colocaciones_por_banco.xlsx y extrae serie mensual."""
    if not os.path.exists(col_path):
        print(f"  AVISO: No se encontró {col_path} — tab Cartera usará datos vacíos")
        return []
    df = pd.read_excel(col_path)
    bancos_map = {
        'BANCO DE CHILE': 'BdCh', 'BANCO SANTANDER-CHILE': 'Sant.',
        'BANCO DE CRÉDITO E INVERSIONES': 'BCI', 'BANCO DEL ESTADO DE CHILE': 'BEst.',
        'ITAÚ CORPBANCA': 'Itaú', 'SCOTIABANK CHILE': 'Scotia'
    }
    df['eu'] = df['entidad'].str.upper().str.strip()
    df = df[df['eu'].isin(bancos_map.keys())].copy()
    df['banco'] = df['eu'].map(bancos_map)
    df['monto'] = df['monto_total'].astype(float)
    cuentas = ['Deudores_TC','Colocaciones_consumo_total','Colocaciones_comerciales',
               'Colocaciones_vivienda','Total_colocaciones','Provisiones_total']
    df = df[df['cuenta'].isin(cuentas)]
    records = []
    for per in sorted(df['periodo'].unique()):
        df_p = df[df['periodo'] == per]
        for banco in bancos_map.values():
            db = df_p[df_p['banco'] == banco]
            def gm(c):
                v = db[db['cuenta'] == c]['monto'].values
                return round(float(v[0]) / 1e6, 0) if len(v) > 0 else None
            records.append({'p': per, 'b': banco,
                'tc': gm('Deudores_TC'), 'con': gm('Colocaciones_consumo_total'),
                'com': gm('Colocaciones_comerciales'), 'viv': gm('Colocaciones_vivienda'),
                'tot': gm('Total_colocaciones'), 'prov': gm('Provisiones_total')})
    print(f"  Colocaciones: {len(records)} registros ({sorted(df['periodo'].unique())[0]} a {sorted(df['periodo'].unique())[-1]})")
    return records


def get_logo_b64(svg_path=None):
    if svg_path and os.path.exists(svg_path):
        with open(svg_path, 'r', encoding='utf-8') as f:
            svg = f.read()
        svg = re.sub(r'<\?xml[^>]+\?>', '', svg)
        svg = re.sub(r'<!--[^>]+-->', '', svg)
        svg = re.sub(r'<sodipodi:[^/]+/>', '', svg)
        svg = re.sub(r'<metadata[^<]+</metadata>', '', svg, flags=re.DOTALL)
        svg = re.sub(r'sodipodi:\w+="[^"]*"', '', svg)
        svg = re.sub(r'inkscape:\w+="[^"]*"', '', svg)
        svg = re.sub(r'xml:space="[^"]*"', '', svg)
        svg = re.sub(r'xmlns:\w+="[^"]*"', '', svg)
        svg = re.sub(r'rdf:\w+="[^"]*"', '', svg)
        svg = re.sub(r'\s+', ' ', svg).strip()
        svg = svg.replace('fill="#002464"', 'fill="white"')
        b = b64lib.b64encode(svg.encode()).decode()
        return f"data:image/svg+xml;base64,{b}"
    return "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 200 30'%3E%3Ctext x='0' y='22' fill='white' font-family='sans-serif' font-size='16' font-weight='bold'%3EBanco de Chile%3C/text%3E%3C/svg%3E"

