def generate_html(data_json, logo_b64):
    a1 = b64lib.b64decode(_B1).decode('utf-8')
    a2 = b64lib.b64decode(_B2).decode('utf-8')
    return HTML_HEAD + "const _D=" + data_json + ";" + a1 + 'const LOGO="' + logo_b64 + '";\n' + a2


def main():
    p = argparse.ArgumentParser(description='Genera dashboard BenchmarkCMF')
    p.add_argument('--consolidado', default='CMF_Tarjetas_Consolidado.xlsx')
    p.add_argument('--logo', default='Banco_de_Chile_Logotipo.svg')
    p.add_argument('--output', default='dashboard/index.html')
    p.add_argument('--meses', type=int, default=24)
    p.add_argument('--colocaciones', default='api_cmf_colocaciones_por_banco.xlsx')
    a = p.parse_args()

    print(f"\n{'='*60}")
    print(f"  BenchmarkCMF — Dashboard Generator")
    print(f"{'='*60}")
    print(f"  Input:  {a.consolidado}")
    print(f"  Output: {a.output}")
    print(f"  Meses:  {a.meses}\n")

    if not os.path.exists(a.consolidado):
        print(f"  ERROR: No se encontro {a.consolidado}")
        sys.exit(1)

    data_json, last_month = extract_data(a.consolidado, a.meses, col_path=a.colocaciones)
    logo = get_logo_b64(a.logo if os.path.exists(a.logo) else None)
    print(f"  Logo: {'SVG cargado' if os.path.exists(a.logo) else 'fallback texto'}")
    print("  Generando HTML...")
    html = generate_html(data_json, logo)
    os.makedirs(os.path.dirname(a.output) or '.', exist_ok=True)
    with open(a.output, 'w', encoding='utf-8') as f:
        f.write(html)
    sz = os.path.getsize(a.output)
    print(f"  Escrito: {a.output} ({sz:,} bytes / {sz//1024} KB)")
    print(f"\n  ✅ Dashboard generado — periodo hasta {last_month}")
    print(f"  Siguiente paso: git add + commit + push\n")

if __name__ == '__main__':
    main()
